SELECT COUNT(*)
FROM repository_setting
WHERE project_id = #{projectId}

SELECT COUNT(*)
FROM repository_setting
WHERE company_id = #{companyId}
  AND project_id = #{projectId}
  AND (repository_identifier = #{repositoryName}
       OR repository_url = #{repositoryUrl})

SELECT COUNT(*)
FROM repository_setting
WHERE company_id = #{companyId}
  AND project_id = #{projectId}
  AND repository_identifier = #{repositoryName}
  AND repository_id != #{repositoryId}

SELECT task_id AS taskId,
       task_title AS taskTitle
FROM task
WHERE project_id = #{projectId}
  AND task_id IN

      #{taskId}

mapper.update:
UPDATE repository_setting
SET repository_main_yn = 'N'
WHERE company_id = #{companyId}
  AND project_id = #{projectId}
  AND repository_main_yn = 'Y'

UPDATE repository_setting
SET repository_identifier = #{repositoryName},
    repository_main_yn = #{mainYn}
WHERE company_id = #{companyId}
  AND project_id = #{projectId}
  AND repository_id = #{repositoryId}

mapper.delete:
DELETE FROM repository_setting
WHERE company_id = #{companyId}
  AND project_id = #{projectId}
  AND repository_id = #{repositoryId}
